import React from "react";
import Navbar from "./components/Navbar";
import SearchForm from "./components/SearchForm";

function App() {
  return (
    <div>
      <Navbar />
      <div className="app-container" style={{ display: "flex", gap: "20px", padding: "20px" }}>
        <SearchForm />
      </div>
    </div>
  );
}

export default App;
